1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	type Item = {
13	  type: string;
14	  material?: string;
15	  enchantment?: number;
16	  cursed?: boolean;
17	};
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
20	
21	const BLOCK_SIZE = 3;
22	const BLOCK_PREMIUM = 60;
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	const CURSED_RATE = 0.5;
26	const HIGH_ENCHANTMENT_THRESHOLD = 5;
27	const HIGH_ENCHANTMENT_RATE = 0.3;
28	
29	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
30	  { applies: (item) => item.cursed === true, rate: CURSED_RATE },
31	  {
32	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
33	    rate: HIGH_ENCHANTMENT_RATE,
34	  },
35	];
36	
37	const groupByType = (items: Item[]): Map<string, Item[]> => {
38	  const groups = new Map<string, Item[]>();
39	  for (const item of items) {
40	    const group = groups.get(item.type) ?? [];
41	    group.push(item);
42	    groups.set(item.type, group);
43	  }
44	  return groups;
45	};
46	
47	const premiumForGroup = (type: string, group: Item[]) => {
48	  if (COMPONENT_TYPES.has(type) && group.length === BLOCK_SIZE) {
49	    return BLOCK_PREMIUM;
50	  }
51	  return group.length * BASE_PREMIUM[type];
52	};
53	
54	const itemSurcharges = (item: Item) => {
55	  const base = BASE_PREMIUM[item.type];
56	  return SURCHARGE_RULES.reduce(
57	    (sum, rule) => (rule.applies(item) ? sum + base * rule.rate : sum),
58	    0,
59	  );
60	};
61	
62	const policyBasePremium = (items: Item[]) =>
63	  [...groupByType(items)].reduce(
64	    (total, [type, group]) => total + premiumForGroup(type, group),
65	    0,
66	  );
67	
68	const sumItemSurcharges = (items: Item[]) =>
69	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
70	
71	const FIRST_INSURANCE_RATE = 0.1;
72	
73	const quote = (step: QuoteStep) => {
74	  const policyBase = policyBasePremium(step.items);
75	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
76	  const itemSurchargeTotal = sumItemSurcharges(step.items);
77	  const premium = policyBase + firstInsurance + itemSurchargeTotal;
78	  return { premium: Math.ceil(premium) + PROCESSING_FEE };
79	};
80	
81	export const run = (input: Scenario): unknown => ({
82	  results: input.steps.map(quote),
83	});
